mapper.select:
SELECT appointment_id, customer_id, staff_id, service_id,
       appointment_date, start_time, end_time, end_datetime,
       total_duration, total_days, billing_type,
       service_address, special_requirements, status, total_amount,
       create_time, update_time
FROM appointment

    AND customer_id = #{customerId}
    AND staff_id = #{staffId}
    AND status = #{status}
    AND appointment_date >= #{startDate}
    AND appointment_date <= #{endDate}

ORDER BY appointment_date DESC, start_time DESC
